{
    "title": "Massimotrava Privacy Policy",
    "is_active": true,
    "items": [
        {
            "id": 1,
            "heading": "Information We Collect",
            "content": "a. Information You Provide: - Name and email address - Account registration details - Goals, habits, preferences, and wellness-related inputs - Images or visual content you choose to upload - Customer support communications b. Information Collected Automatically: - Device and browser information - App and website usage data - IP address - Cookies and similar technologies (website only)"
        },
        {
            "id": 2,
            "heading": "How We Use Your Information",
            "content": "We use your information to: - Provide and maintain the Services - Personalize your experience - Improve functionality and performance - Send notifications or communications you opt into - Respond to support or privacy requests"
        },
        
        {
            "id": 3,
            "heading": "Sharing of Information",
            "content": "We may share information only: - With service providers who support platform operations - When required by law - To protect rights, safety, or security We do not sell personal data."
        },
        
        {
            "id": 4,
            "heading": "Data Security",
            "content": "We implement administrative, technical, and organizational safeguards. However, no system is 100% secure."
        },
        {
            "id": 5,
            "heading": "Data Retention",
            "content": "We retain data only as long as necessary to: - Provide Services - Meet legal obligations You can request deletion anytime."
        },
        {
            "id": 6,
            "heading": "Your Rights",
            "content": "You may have rights to: - Access data - Correct data - Delete data - Opt out of communications Contact us via email below."
        },
        {
            "id": 7,
            "heading": "Children’s Privacy",
            "content": "Massimotrava is not intended for individuals under 18."
        },
        {
            "id": 8,
            "heading": "Policy Updates",
            "content": "We collect information you provide such as name, email address, goals, and health related inputs."
        },
        {
            "id": 9,
            "heading": "Contact",
            "content": "For privacy questions: 📧 massimotravaSupport@gmail.com"
        }
    ]
}

